async function getAutocompleteSuggestions(query) {
  try {
    const response = await axios.get(`${config.apiEndpoint}find`, {
      params: {
        q: query,
        appid: config.apiKey
      }
    });
    return response.data.list.map(item => item.name);
  } catch (error) {
    handleError(error);
    return [];
  }
}

function updateSuggestions(suggestions) {
