```javascript
async function fetchWeatherData(city) {
  const apiUrl = `https://api.openweathermap.org/data/2.5/weather?q=${city}&units=metric&appid=MY_API_KEY`;
  let attempts = 0;
  const maxAttempts = 3;
  const initialDelay = 1000; // 1 second initial delay

  while (attempts < maxAttempts) {
    try {
      const response = await fetch(apiUrl);

      if (!response.ok) {
        const errorData = await response.json();
        const errorMessage = errorData.message || `HTTP error! status: ${response.status}`;
        throw new Error(errorMessage);
      }

      const jsonData = await response.json();
      return jsonData;
    } catch (error) {
      if (error instanceof TypeError) {
        console.error('Network error:', error);
        throw new Error('Network error occurred while fetching weather data.');
      } else if (error.response && error.response.status === 401) {
        console.error('Unauthorized error:', error);
        throw new Error('Unauthorized access. Please check your API key.');
      } else {
        console.error('Error fetching weather data:', error);
        attempts++;
        const delay = initialDelay * Math.pow(2, attempts) + Math.random() * 1000; // Exponential backoff with jitter
        console.warn(`Attempt ${attempts}/${maxAttempts} failed. Retrying in ${delay / 1000} seconds...`);
        await new Promise(resolve => setTimeout(resolve, delay));
      }
    }
  }

  throw new Error('Failed to fetch weather data after multiple attempts.');
}
```

