import pako from 'pako';

class Cache {
  constructor(limit = 5 * 1024 * 1024) { // 5MB limit
    this.cache = {};
    this.timestamp = {};
    this.limit = limit;
  }

  get(key) {
    if (this.cache[key] && this.timestamp[key] > Date.now() - 3600000) {
      return this.cache[key];
    }
    return null;
  }

  set(key, value) {
    const compressedValue = pako.deflate(JSON.stringify(value));
    this.cache[key] = compressedValue;
    this.timestamp[key] = Date.now();
    this.persist();
    this.evictIfNecessary();
  }

  persist() {
    localStorage.setItem('cache', JSON.stringify(Object.keys(this.cache)));
    localStorage.setItem('timestamp', JSON.stringify(this.timestamp));
    Object.keys(this.cache).forEach(key => {
      localStorage.setItem(key, this.cache[key]);
    });
  }

  evictIfNecessary() {
    let totalSize = 0;
    Object.keys(this.cache).forEach(key => {
      totalSize += this.cache[key].length;
    });

    if (totalSize > this.limit) {
      this.evictLeastRecentlyUsed();
    }
  }

  evictLeastRecentlyUsed() {
    const keys = Object.keys(this.timestamp);
    keys.sort((a, b) => this.timestamp[a] - this.timestamp[b]);

    for (let i = 0; i < keys.length; i++) {
      const key = keys[i];
      delete this.cache[key];
      delete this.timestamp[key];
      localStorage.removeItem(key);
      localStorage.removeItem('cache');
      localStorage.removeItem('timestamp');
      this.persist();
      if (this.totalSize() <= this.limit) {
        break;
      }
    }
  }

  totalSize() {
    let totalSize = 0;
    Object.keys(this.cache).forEach(key => {
      totalSize += this.cache[key].length;
    });
    return totalSize;
  }

  clear() {
    this.cache = {};
    this.timestamp = {};
    localStorage.removeItem('cache');
    localStorage.removeItem('timestamp');
    Object.keys(localStorage).forEach(key => {
      if (key !== 'cache' && key !== 'timestamp') {
        localStorage.removeItem(key);
      }
    });
  }

  decompress(compressedValue) {
    const decompressedValue = pako.inflate(compressedValue, { to: 'string' });
    return JSON.parse(decompressedValue);
  }
