  await cache.set('New York', { temperature: 25, humidity: 60, timestamp: Date.now() });
  await cache.set('London', { temperature: 18, humidity: 80, timestamp: Date.now() });
  await cache.set('Paris', { temperature: 22, humidity: 70, timestamp: Date.now() });

  console.log(await cache.get('New York'));
})();
```

### Explanation

